  font-size: 1.25rem;
  font-weight: 600;
  color: #00d4ff;
}
```

### 4.3 列表样式
```css
ul {
  list-style: none;
  padding: 0;
}

li {
  position: relative;
  padding-left: 20px;
  margin-bottom: 12px;
  color: #94a3b8;
  line-height: 1.6;
}

li::before {
  content: "";
  position: absolute;
  left: 0;
  top: 8px;
  width: 6px;
  height: 6px;
  background: linear-gradient(135deg, #00d4ff, #7c3aed);
  border-radius: 50%;
}
```

### 4.4 数据卡片组件
```css
.data-card {
  background: linear-gradient(135deg, rgba(0,212,255,0.1), rgba(124,58,237,0.1));
  border: 1px solid rgba(0,212,255,0.3);
  border-radius: 12px;
  padding: 20px;
  text-align: center;
